/* ── SheetDB helpers ─────────────────────────────────────────────────── */
async function sheetdbGet(sheet="Ninos"){
  try{
    const r=await fetch(`${SHEETDB_URL}?sheet=${sheet}`);
    if(!r.ok)return null;
    return await r.json();
  }catch(e){ console.log("SheetDB GET error:",e); return null; }
}
async function sheetdbPost(data,sheet="Ninos"){
  try{
    await fetch(SHEETDB_URL,{method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({data,sheet})});
  }catch(e){ console.log("SheetDB POST error:",e); }
}
async function sheetdbPatch(searchCol,searchVal,data,sheet="Ninos"){
  try{
    await fetch(`${SHEETDB_URL}/${searchCol}/${searchVal}?sheet=${sheet}`,
      {method:"PATCH",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({data})});
  }catch(e){ console.log("SheetDB PATCH error:",e); }
}

