function todayStr(){ return new Date().toISOString().slice(0,10); }
function genId5(){ return Math.random().toString(36).substring(2,7).toUpperCase(); }
function pickupCode(childId){
  const seed=childId+todayStr(); let h=0;
  for(let i=0;i<seed.length;i++) h=Math.imul(31,h)+seed.charCodeAt(i)|0;
  return Math.abs(h).toString(36).slice(0,5).toUpperCase();
}
function timeFmt(iso){
  if(!iso)return""; const d=new Date(iso);
  return d.toLocaleTimeString("es-ES",{hour:"2-digit",minute:"2-digit"})+" · "+d.toLocaleDateString("es-ES",{day:"2-digit",month:"short"});
}
function timeHM(iso){ if(!iso)return""; return new Date(iso).toLocaleTimeString("es-ES",{hour:"2-digit",minute:"2-digit"}); }
function ld(k,fb){ try{ const v=localStorage.getItem(k); return v?JSON.parse(v):fb; }catch{ return fb; } }
function sv(k,v){ try{ localStorage.setItem(k,JSON.stringify(v)); }catch{} }
function readF(file){ return new Promise((res,rej)=>{ const r=new FileReader(); r.onload=()=>res(r.result); r.onerror=rej; r.readAsDataURL(file); }); }

