/* ── QR display ──────────────────────────────────────────────────────── */
function QRDraw({value,size=180}){
  const ref=useRef();
  useEffect(()=>{
    if(!ref.current||!value)return;
    const ctx=ref.current.getContext("2d");
    const s=size; ctx.fillStyle="#fff"; ctx.fillRect(0,0,s,s); ctx.fillStyle="#1a1a2e";
    const cell=Math.floor(s/21);
    const hash=[...value].reduce((a,c,i)=>a^(c.charCodeAt(0)*(i+7)),0x5A3B);
    for(let r=0;r<21;r++) for(let c=0;c<21;c++){
      const bit=((hash>>(r*c%32))^(r*7+c*3))&1;
      const fin=(rr,cc)=>(rr<=6&&cc<=6)||(rr<=6&&cc>=14)||(rr>=14&&cc<=6);
      if(fin(r,c)){
        const fr=r<=6?r:r>=14?r-14:r; const fc=c<=6?c:c>=14?c-14:c;
        if(fr===0||fr===6||fc===0||fc===6||(fr>=2&&fr<=4&&fc>=2&&fc<=4))
          ctx.fillRect(c*cell,r*cell,cell,cell);
      } else if(bit) ctx.fillRect(c*cell,r*cell,cell,cell);
    }
  },[value,size]);
  return <canvas ref={ref} width={size} height={size} style={{borderRadius:8,border:"2px solid #e5e7eb"}}/>;
}

/* ── QR scanner ──────────────────────────────────────────────────────── */
function QRScan({onScan,onClose}){
  const vRef=useRef(),cRef=useRef(),streamRef=useRef(null),rafRef=useRef(null);
  const [manual,setManual]=useState("");
  const [camErr,setCamErr]=useState(false);
  const [ready,setReady]=useState(false);

  useEffect(()=>{
    let alive=true;
    function start(){
      const opts=[
        {video:{facingMode:{exact:"environment"}}},
        {video:{facingMode:"environment"}},
        {video:true}
      ];
      function try_(i){
        if(i>=opts.length){setCamErr(true);return;}
        navigator.mediaDevices.getUserMedia(opts[i])
          .then(s=>{
            if(!alive){s.getTracks().forEach(t=>t.stop());return;}
            streamRef.current=s;
            if(vRef.current){vRef.current.srcObject=s;vRef.current.play().then(()=>setReady(true)).catch(()=>setReady(true));}
          }).catch(()=>try_(i+1));
      }
      if(!navigator.mediaDevices?.getUserMedia){setCamErr(true);return;}
      try_(0);
    }
    if(window.jsQR){start();return;}
    const sc=document.createElement("script");
    sc.src="https://cdnjs.cloudflare.com/ajax/libs/jsQR/1.4.0/jsQR.min.js";
    sc.onload=()=>{if(alive)start();};
    sc.onerror=()=>setCamErr(true);
    document.head.appendChild(sc);
    return()=>{alive=false;streamRef.current?.getTracks().forEach(t=>t.stop());cancelAnimationFrame(rafRef.current);};
  },[]);

  useEffect(()=>{
    if(!ready)return;
    function tick(){
      const v=vRef.current,c=cRef.current;
      if(v&&v.readyState===v.HAVE_ENOUGH_DATA&&window.jsQR){
        c.width=v.videoWidth;c.height=v.videoHeight;
        const ctx=c.getContext("2d");ctx.drawImage(v,0,0,c.width,c.height);
        const img=ctx.getImageData(0,0,c.width,c.height);
        const qr=window.jsQR(img.data,img.width,img.height,{inversionAttempts:"dontInvert"});
        if(qr){onScan(qr.data);return;}
      }
      rafRef.current=requestAnimationFrame(tick);
    }
    rafRef.current=requestAnimationFrame(tick);
    return()=>cancelAnimationFrame(rafRef.current);
  },[ready,onScan]);

  return <div>
    <canvas ref={cRef} style={{display:"none"}}/>
    {!camErr&&<div style={{position:"relative",borderRadius:16,overflow:"hidden",background:"#000",marginBottom:14}}>
      <video ref={vRef} style={{width:"100%",maxHeight:240,objectFit:"cover",display:"block"}} playsInline muted/>
      <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",pointerEvents:"none"}}>
        <div style={{width:170,height:170,border:"3px solid #6366f1",borderRadius:16,boxShadow:"0 0 0 2000px #0005"}}/>
      </div>
      <div style={{position:"absolute",bottom:8,left:0,right:0,textAlign:"center",color:"#fff",fontSize:12,fontWeight:600}}>
        {ready?"📷 Apunta al QR":"Iniciando cámara..."}
      </div>
    </div>}
    {camErr&&<div style={{background:"#fef3c7",borderRadius:10,padding:"10px 14px",marginBottom:14,
      color:"#92400e",fontSize:13,border:"1.5px solid #fde68a"}}>
      ⚠️ Cámara no disponible. Usa el código manual.
    </div>}
    <div style={{borderTop:"1px solid #f3f4f6",paddingTop:12}}>
      <Inp label="Código manual del responsable" value={manual} onChange={setManual} placeholder="Ingresa el código"/>
      <div style={{display:"flex",gap:8}}>
        <Btn onClick={()=>manual.trim()&&onScan(manual.trim().toUpperCase())} full>Verificar</Btn>
        <Btn onClick={onClose} outline>Cancelar</Btn>
      </div>
    </div>
  </div>;
}

