/* ── auto notif hook ─────────────────────────────────────────────────── */
function useAutoNotif(sched,kids,msgs,setMsgs){
  useEffect(()=>{
    if(!sched.s2)return;
    const chk=()=>{
      const now=new Date();
      const [h,m]=sched.s2.split(":").map(Number);
      const diff=(now.getHours()*60+now.getMinutes())-(h*60+m);
      if(diff>=0&&diff<2&&!msgs.some(x=>x.auto&&x.date===todayStr())){
        setMsgs(p=>[...p,{id:"a"+Date.now(),title:"🔔 Hora de recoger a los niños",
          body:`Por favor recoja a su niño/a. Horario: ${sched.s2} - ${sched.e2}`,
          to:"all",alert:true,auto:true,date:todayStr(),dis:[],at:new Date().toISOString()}]);
      }
    };
    const iv=setInterval(chk,60000);chk();
    return()=>clearInterval(iv);
  },[sched,msgs]);
}

/* ══════════════════════════════════════════════════════════════════════
   LOGIN
══════════════════════════════════════════════════════════════════════ */
function Login({users,onLogin,onReg}){
  const [mode,setMode]=useState("login");
  const [email,setEmail]=useState("");
  const [pass,setPass]=useState("");
  const [name,setName]=useState("");
  const [err,setErr]=useState("");

  const iStyle={width:"100%",background:"rgba(255,255,255,.08)",border:"2px solid rgba(255,255,255,.12)",
    borderRadius:10,padding:"10px 14px",fontSize:14,fontFamily:"inherit",color:"#fff",outline:"none",boxSizing:"border-box"};
  const focus=e=>e.target.style.borderColor="#6366f1";
  const blur=e=>e.target.style.borderColor="rgba(255,255,255,.12)";

  function doLogin(){
    const u=users.find(u=>u.email.toLowerCase()===email.toLowerCase()&&u.password===pass);
    if(!u){setErr("Email o contraseña incorrectos.");return;}
    if(u.pending||u.role==="pending"){setErr("⏳ Tu cuenta está pendiente de aprobación por un administrador.");return;}
    onLogin(u);setErr("");
  }
  const [inviteCode,setInviteCode]=useState("");
  const [wantAdmin,setWantAdmin]=useState(false);

  function doReg(){
    if(!name||!email||!pass){setErr("Completa todos los campos.");return;}
    if(users.find(u=>u.email.toLowerCase()===email.toLowerCase())){setErr("Email ya registrado.");return;}
    if(wantAdmin && inviteCode!==ADMIN_INVITE_CODE){setErr("Código de administrador incorrecto.");return;}
    const role=wantAdmin?"admin":"pending";
    onReg({id:"u"+Date.now(),email,password:pass,role,name,childrenIds:[],pending:!wantAdmin});
    if(!wantAdmin) setErr("✅ Cuenta creada. Un administrador debe aprobarte antes de acceder.");
  }

  return <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#1a1a2e,#16213e,#0f3460)",
    display:"flex",alignItems:"center",justifyContent:"center",padding:16,fontFamily:"'DM Sans',sans-serif"}}>
    <style>{CSS}</style>
    <div style={{width:"100%",maxWidth:400,animation:"fUp .4s ease"}}>
      <div style={{textAlign:"center",marginBottom:28}}>
        <div style={{width:80,height:80,borderRadius:22,overflow:"hidden",margin:"0 auto 14px",
          boxShadow:"0 8px 32px #0005",border:"2px solid rgba(255,255,255,.2)"}}>
          <img src={LOGO_SRC} alt="logo" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
        </div>
        <div style={{color:"#fff",fontFamily:"Syne,sans-serif",fontWeight:800,fontSize:22}}>Iglesia La Hermosa</div>
        <div style={{color:"#a5b4fc",fontSize:13,marginTop:3}}>Ministerio Infantil</div>
      </div>
      <div style={{background:"rgba(255,255,255,.07)",backdropFilter:"blur(20px)",borderRadius:20,
        padding:"26px 22px",border:"1px solid rgba(255,255,255,.12)"}}>
        <div style={{display:"flex",background:"rgba(0,0,0,.2)",borderRadius:10,padding:3,marginBottom:20}}>
          {["login","register"].map(m=>(
            <button key={m} onClick={()=>{setMode(m);setErr("");}} style={{flex:1,border:"none",
              background:mode===m?"#fff":"transparent",color:mode===m?"#1a1a2e":"#a5b4fc",
              borderRadius:8,padding:"8px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
              {m==="login"?"Iniciar sesión":"Crear cuenta"}
            </button>
          ))}
        </div>
        {mode==="register"&&<div style={{marginBottom:12}}>
          <label style={{display:"block",fontSize:11,fontWeight:700,color:"#a5b4fc",marginBottom:5,letterSpacing:.5}}>NOMBRE *</label>
          <input value={name} onChange={e=>setName(e.target.value)} placeholder="Tu nombre completo" style={iStyle} onFocus={focus} onBlur={blur}/>
        </div>}
        {[["email","EMAIL *","tu@email.com","email"],["pass","CONTRASEÑA *","••••••••","password"]].map(([k,l,pl,t])=>(
          <div key={k} style={{marginBottom:12}}>
            <label style={{display:"block",fontSize:11,fontWeight:700,color:"#a5b4fc",marginBottom:5,letterSpacing:.5}}>{l}</label>
            <input type={t} value={k==="email"?email:pass}
              onChange={e=>k==="email"?setEmail(e.target.value):setPass(e.target.value)}
              placeholder={pl} style={iStyle}
              onKeyDown={e=>e.key==="Enter"&&(mode==="login"?doLogin():doReg())}
              onFocus={focus} onBlur={blur}/>
          </div>
        ))}
        {mode==="register"&&<div style={{marginBottom:12}}>
          <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",
            background:"rgba(255,255,255,.05)",borderRadius:10,padding:"10px 12px",
            border:`1.5px solid ${wantAdmin?"#a78bfa":"rgba(255,255,255,.1)"}`}}>
            <input type="checkbox" checked={wantAdmin} onChange={e=>setWantAdmin(e.target.checked)}
              style={{accentColor:"#a78bfa",width:16,height:16}}/>
            <div>
              <div style={{color:"#fff",fontSize:13,fontWeight:700}}>Registrarme como Administrador</div>
              <div style={{color:"#a5b4fc",fontSize:11}}>Requiere código de invitación</div>
            </div>
          </label>
          {wantAdmin&&<div style={{marginTop:8}}>
            <label style={{display:"block",fontSize:11,fontWeight:700,color:"#a5b4fc",marginBottom:5,letterSpacing:.5}}>CÓDIGO DE INVITACIÓN *</label>
            <input value={inviteCode} onChange={e=>setInviteCode(e.target.value.toUpperCase())}
              placeholder="Código secreto de admin" style={{...iStyle,letterSpacing:2,fontFamily:"monospace"}}
              onFocus={e=>e.target.style.borderColor="#a78bfa"} onBlur={e=>e.target.style.borderColor="rgba(255,255,255,.12)"}/>
          </div>}
        </div>}
        {err&&<div style={{background:err.startsWith("✅")?"rgba(34,197,94,.15)":"rgba(239,68,68,.15)",
          border:`1px solid ${err.startsWith("✅")?"rgba(34,197,94,.3)":"rgba(239,68,68,.3)"}`,
          borderRadius:8,padding:"8px 12px",marginBottom:10,
          color:err.startsWith("✅")?"#86efac":"#fca5a5",fontSize:13}}>{err}</div>}
        <Btn onClick={mode==="login"?doLogin:doReg} full color="#6366f1" style={{marginTop:6}}>
          {mode==="login"?"Entrar →":"Crear cuenta"}
        </Btn>
        {mode==="login"&&<div style={{marginTop:14,padding:"10px 12px",background:"rgba(255,255,255,.05)",borderRadius:10}}>
          <div style={{color:"#a5b4fc",fontSize:10,fontWeight:700,marginBottom:4}}>CUENTAS DEMO</div>
          <div style={{color:"#cbd5e1",fontSize:11}}>Admin: admin@iglesia.com / admin123</div>
          <div style={{color:"#cbd5e1",fontSize:11}}>Padre: maria@email.com / maria123</div>
        </div>}
      </div>
    </div>
  </div>;
}

/* ══════════════════════════════════════════════════════════════════════
   PARENT VIEW
══════════════════════════════════════════════════════════════════════ */
function ParentView({user,kids,resps,msgs,setMsgs,sched,onOut}){
  const myKids=kids.filter(c=>user.childrenIds?.includes(c.id));
  const [sel,setSel]=useState(null);
  useEffect(()=>{if(myKids.length&&!sel)setSel(myKids[0]);},[myKids.length]);
  function dis(id){setMsgs(p=>p.map(m=>m.id===id?{...m,dis:[...(m.dis||[]),user.id]}:m));}

  if(!myKids.length)return <div style={{minHeight:"100vh",display:"flex",alignItems:"center",
    justifyContent:"center",fontFamily:"'DM Sans',sans-serif",background:"#f0f2f8"}}>
    <style>{CSS}</style>
    <div style={{textAlign:"center",padding:32}}>
      <div style={{fontSize:48,marginBottom:12}}>👶</div>
      <div style={{fontFamily:"Syne",fontWeight:800,fontSize:19,color:"#1a1a2e",marginBottom:8}}>Sin niños vinculados</div>
      <div style={{color:"#6b7280",fontSize:13,marginBottom:18}}>Pide al administrador que vincule tu cuenta.</div>
      <Btn onClick={onOut} outline>Cerrar sesión</Btn>
    </div>
  </div>;

  const kid=sel||myKids[0];
  const g=groupOf(kid);
  const code=pickupCode(kid.id);
  const myR=resps.find(r=>r.uid===user.id);
  const qrCode=myR?(myR.id+todayStr()).slice(0,8).toUpperCase():"";
  const lastOut=[...(kid.log||[])].reverse().find(a=>a.t==="out");
  const myMsgs=msgs.filter(m=>(m.to==="all"||m.to===user.id)&&!m.dis?.includes(user.id));

  return <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#f0f2f8,#e8eaf6)",fontFamily:"'DM Sans',sans-serif"}}>
    <style>{CSS}</style>
    <Banner msgs={msgs} uid={user.id} onDismiss={dis}/>
    <header style={{background:"#1a1a2e",padding:"0 16px",height:56,display:"flex",
      alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:800}}>
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        <Logo size={32}/>
        <span style={{color:"#fff",fontFamily:"Syne",fontWeight:800,fontSize:15}}>Iglesia La Hermosa</span>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        {myMsgs.length>0&&<span style={{background:"#ef4444",color:"#fff",borderRadius:"50%",
          width:20,height:20,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700}}>
          {myMsgs.length}</span>}
        <span style={{color:"#a5b4fc",fontSize:12}}>{user.name.split(" ")[0]}</span>
        <button onClick={onOut} style={{border:"1px solid rgba(255,255,255,.2)",background:"transparent",
          color:"#a5b4fc",borderRadius:8,padding:"4px 10px",fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>Salir</button>
      </div>
    </header>
    <div style={{maxWidth:480,margin:"0 auto",padding:"18px 14px",animation:"fIn .3s ease"}}>
      {myKids.length>1&&<div style={{display:"flex",gap:8,marginBottom:14,overflowX:"auto"}}>
        {myKids.map(k=><button key={k.id} onClick={()=>setSel(k)} style={{
          background:sel?.id===k.id?"#6366f1":"#fff",color:sel?.id===k.id?"#fff":"#374151",
          border:`2px solid ${sel?.id===k.id?"#6366f1":"#e5e7eb"}`,
          borderRadius:99,padding:"5px 14px",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>
          {k.name.split(" ")[0]}
        </button>)}
      </div>}
      {myMsgs.length>0&&<div style={{marginBottom:14}}>
        {myMsgs.map(m=><div key={m.id} style={{background:m.alert?"#fef2f2":"#f0fdf4",
          border:`1.5px solid ${m.alert?"#fecaca":"#bbf7d0"}`,borderRadius:14,
          padding:"11px 14px",marginBottom:8,display:"flex",gap:10,alignItems:"flex-start"}}>
          <span style={{fontSize:20}}>{m.alert?"🔔":"📢"}</span>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{m.title}</div>
            {m.body&&<div style={{fontSize:12,color:"#6b7280",marginTop:2}}>{m.body}</div>}
          </div>
          <button onClick={()=>dis(m.id)} style={{border:"none",background:"none",cursor:"pointer",color:"#9ca3af",fontSize:14}}>✕</button>
        </div>)}
      </div>}
      {/* Kid card */}
      <div style={{background:"#fff",borderRadius:20,padding:"20px",boxShadow:"0 4px 20px #0002",
        marginBottom:14,border:`2px solid ${g.color}20`}}>
        <div style={{display:"flex",gap:12,alignItems:"center",marginBottom:16}}>
          <Ava photo={kid.photo} emoji={g.emoji} color={g.color} size={56}/>
          <div>
            <div style={{fontFamily:"Syne",fontWeight:800,fontSize:18,color:"#1a1a2e"}}>{kid.name}</div>
            <div style={{display:"flex",gap:6,marginTop:4,alignItems:"center",flexWrap:"wrap"}}>
              <Badge g={g}/>
              <span style={{fontSize:11,color:"#9ca3af"}}>{kid.gender==="nina"?"👧 Niña":"👦 Niño"}</span>
              <Dot on={kid.in}/><span style={{fontSize:11,color:"#9ca3af"}}>{kid.in?"Dentro":"Fuera"}</span>
            </div>
            <div style={{marginTop:4,fontSize:11,color:"#6b7280"}}>ID: <span style={{fontFamily:"monospace",fontWeight:700,color:"#374151"}}>{kid.cid}</span></div>
          </div>
        </div>
        <div style={{background:"linear-gradient(135deg,#6366f1,#a78bfa)",borderRadius:14,padding:"14px 18px",marginBottom:12}}>
          <div style={{color:"rgba(255,255,255,.7)",fontSize:10,fontWeight:700,letterSpacing:1,marginBottom:4}}>CÓDIGO DE RECOGIDA HOY</div>
          <div style={{color:"#fff",fontFamily:"Syne",fontWeight:800,fontSize:34,letterSpacing:8}}>{code}</div>
          <div style={{color:"rgba(255,255,255,.6)",fontSize:11,marginTop:3}}>Válido hoy · cambia cada día a medianoche</div>
        </div>
        {sched.s1&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
          <div style={{background:"#f0fdf4",borderRadius:10,padding:"9px 12px",border:"1.5px solid #bbf7d0"}}>
            <div style={{fontSize:10,fontWeight:700,color:"#16a34a",marginBottom:2}}>ENTRADA</div>
            <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{sched.s1} – {sched.e1}</div>
          </div>
          <div style={{background:"#fef3c7",borderRadius:10,padding:"9px 12px",border:"1.5px solid #fde68a"}}>
            <div style={{fontSize:10,fontWeight:700,color:"#d97706",marginBottom:2}}>RECOGIDA</div>
            <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{sched.s2} – {sched.e2}</div>
          </div>
        </div>}
        {kid.allergies&&<div style={{background:"#fef2f2",borderRadius:10,padding:"8px 12px",
          border:"1.5px solid #fecaca",marginBottom:8,fontSize:13,color:"#dc2626",fontWeight:600}}>⚠️ Alergia: {kid.allergies}</div>}
        {kid.notes&&<div style={{background:"#f0f9ff",borderRadius:10,padding:"8px 12px",
          border:"1.5px solid #bae6fd",fontSize:13,color:"#0369a1"}}>📝 {kid.notes}</div>}
      </div>
      {/* Last pickup */}
      <div style={{background:"#fff",borderRadius:16,padding:"15px 18px",boxShadow:"0 2px 10px #0001",marginBottom:14}}>
        <div style={{fontFamily:"Syne",fontWeight:700,fontSize:14,color:"#1a1a2e",marginBottom:10}}>Última recogida</div>
        {lastOut?<div style={{display:"flex",gap:10,alignItems:"center"}}>
          <div style={{width:36,height:36,borderRadius:10,background:"#dcfce7",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>✅</div>
          <div>
            <div style={{fontWeight:600,fontSize:14,color:"#1a1a2e"}}>{lastOut.by}</div>
            <div style={{fontSize:12,color:"#6b7280"}}>{timeFmt(lastOut.at)}</div>
          </div>
        </div>:<div style={{color:"#9ca3af",fontSize:13}}>Sin recogidas registradas.</div>}
      </div>
      {/* History */}
      {kid.log?.length>0&&<div style={{background:"#fff",borderRadius:16,padding:"15px 18px",boxShadow:"0 2px 10px #0001",marginBottom:14}}>
        <div style={{fontFamily:"Syne",fontWeight:700,fontSize:14,color:"#1a1a2e",marginBottom:10}}>Historial reciente</div>
        {[...kid.log].reverse().slice(0,8).map((a,i)=>(
          <div key={i} style={{display:"flex",gap:8,alignItems:"center",fontSize:13,marginBottom:5,
            paddingBottom:5,borderBottom:i<7?"1px solid #f3f4f6":"none"}}>
            <span style={{fontSize:14}}>{a.t==="in"?"🟢":"🔵"}</span>
            <div style={{flex:1}}>
              <span style={{fontWeight:600,color:"#1a1a2e"}}>{a.t==="in"?"Entrada":"Salida"}</span>
              {a.by&&<span style={{color:"#6b7280"}}> · {a.by}</span>}
            </div>
            <span style={{color:"#9ca3af",fontSize:11,whiteSpace:"nowrap"}}>{timeFmt(a.at)}</span>
          </div>
        ))}
      </div>}
      {/* QR */}
      {myR&&<div style={{background:"#fff",borderRadius:16,padding:"15px 18px",boxShadow:"0 2px 10px #0001"}}>
        <div style={{fontFamily:"Syne",fontWeight:700,fontSize:14,color:"#1a1a2e",marginBottom:2}}>Mi QR de hoy</div>
        <div style={{color:"#6b7280",fontSize:12,marginBottom:14}}>Muéstralo al profesor al recoger — válido solo hoy</div>
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10}}>
          <QRDraw value={qrCode} size={160}/>
          <div style={{fontFamily:"monospace",fontWeight:800,fontSize:20,color:"#6366f1",letterSpacing:4}}>{qrCode}</div>
        </div>
      </div>}
    </div>
  </div>;
}

/* ══════════════════════════════════════════════════════════════════════
   ADMIN VIEW
══════════════════════════════════════════════════════════════════════ */
function AdminView({user,users,setUsers,kids,setKids,resps,setResps,msgs,setMsgs,sched,setSched,onOut}){
  /* sheets */
  const [sheetsUrl,setSheetsUrl]=useState(()=>ld("mi_su",""));
  useEffect(()=>sv("mi_su",sheetsUrl),[sheetsUrl]);
  async function push(rows,sheet="Asistencia"){
    if(!sheetsUrl)return;
    try{await fetch(sheetsUrl,{method:"POST",mode:"no-cors",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({sheet,rows})});}catch(e){}
  }
  const [stStatus,setStStatus]=useState("");
  function exportCSV(){
    const rows=kids.map(c=>{
      const rn=resps.filter(r=>c.rids.includes(r.id)).map(r=>r.name).join(", ");
      const lo=[...(c.log||[])].reverse().find(a=>a.t==="out");
      return {ID:c.cid,Nombre:c.name,Edad:c.age,Sexo:c.gender==="nina"?"Niña":"Niño",
        Grupo:groupOf(c).label,Estado:c.in?"Dentro":"Fuera",Alergias:c.allergies||"",
        Notas:c.notes||"",Responsables:rn,UltimaRecogida:lo?lo.by:"",
        HoraRecogida:lo?timeFmt(lo.at):"",CodigoHoy:pickupCode(c.id),Fecha:todayStr()};
    });
    // Send to SheetDB
    sheetdbPost(rows,"Asistencia").then(()=>setStStatus("✅ Enviado a Google Sheets"));
    // Also download CSV
    const h=Object.keys(rows[0]||{});
    const csv=[h.join(","),...rows.map(r=>h.map(k=>'"'+(r[k]||"")+'"').join(","))].join("\n");
    const a=document.createElement("a");
    a.href=URL.createObjectURL(new Blob([csv],{type:"text/csv;charset=utf-8;"}));
    a.download=`asistencia-${todayStr()}.csv`;a.click();
    setStStatus("✅ Enviado a Sheets + 📥 CSV descargado");
    setTimeout(()=>setStStatus(""),4000);
  }

  /* state */
  const [tab,setTab]=useState("dashboard");
  const [search,setSearch]=useState("");
  const [fG,setFG]=useState("all");
  const [addKid,setAddKid]=useState(false);
  const [dKid,setDKid]=useState(null);
  const [addR,setAddR]=useState(false);
  const [scanOpen,setScanOpen]=useState(false);
  const [scanRes,setScanRes]=useState(null);
  const [coKid,setCoKid]=useState(null);
  const [msgMod,setMsgMod]=useState(false);
  const [schedMod,setSchedMod]=useState(false);
  const [sheetsMod,setSheetsMod]=useState(false);
  const [msgSearch,setMsgSearch]=useState("");

  const eKid={name:"",age:"",gender:"nino",allergies:"",notes:""};
  const eResp={name:"",phone:"",email:"",rel:"",nApp:true,nSms:false,uid:""};
  const eMsg={title:"",body:"",to:"all",toUid:"",toKid:""};
  const [kF,setKF]=useState(eKid);
  const [rF,setRF]=useState(eResp);
  const [mF,setMF]=useState(eMsg);
  const [scF,setScF]=useState(sched);

  useAutoNotif(sched,kids,msgs,setMsgs);

  const cin=kids.filter(c=>c.in).length;
  const filt=kids.filter(c=>(fG==="all"||groupOf(c).id===fG)&&c.name.toLowerCase().includes(search.toLowerCase()));

  function saveKid(){
    if(!kF.name||!kF.age)return;
    const nk={id:"k"+Date.now(),cid:genId5(),name:kF.name,age:Number(kF.age),
      gender:kF.gender,allergies:kF.allergies,notes:kF.notes,rids:[],in:false,photo:null,log:[]};
    setKids(p=>[...p,nk]);
    // Sync to SheetDB
    sheetdbPost({ID:nk.cid,Nombre:nk.name,Edad:nk.age,Sexo:nk.gender==="nina"?"Niña":"Niño",
      Grupo:groupOf(nk).label,Alergias:nk.allergies||"",Notas:nk.notes||"",
      Estado:"Fuera",Fecha:todayStr()},"Ninos");
    setKF(eKid);setAddKid(false);
  }
  function saveResp(kid){
    if(!rF.name)return;
    const nr={id:"r"+Date.now(),name:rF.name,phone:rF.phone,email:rF.email,
      rel:rF.rel,nApp:rF.nApp,nSms:rF.nSms,uid:rF.uid||null};
    setResps(p=>[...p,nr]);
    setKids(p=>p.map(c=>c.id===kid.id?{...c,rids:[...c.rids,nr.id]}:c));
    if(rF.uid)setUsers(p=>p.map(u=>u.id===rF.uid?{...u,childrenIds:[...(u.childrenIds||[]),kid.id]}:u));
    setRF(eResp);setAddR(false);
    setDKid(p=>p?{...p,rids:[...p.rids,nr.id]}:p);
  }
  function delKid(id){setKids(p=>p.filter(c=>c.id!==id));setDKid(null);}
  function delResp(rid,kid){
    setResps(p=>p.filter(r=>r.id!==rid));
    setKids(p=>p.map(c=>c.id===kid.id?{...c,rids:c.rids.filter(x=>x!==rid)}:c));
    setDKid(p=>p?{...p,rids:p.rids.filter(x=>x!==rid)}:p);
  }
  function doIn(id){
    const now=new Date().toISOString();
    const k=kids.find(c=>c.id===id);
    setKids(p=>p.map(c=>c.id===id?{...c,in:true,log:[...(c.log||[]),{t:"in",at:now,by:user.name}]}:c));
    setDKid(p=>p&&p.id===id?{...p,in:true,log:[...(p.log||[]),{t:"in",at:now,by:user.name}]}:p);
    if(k){
      // Log movement
      sheetdbPost({ID:k.cid,Nombre:k.name,Evento:"Entrada",Por:user.name,
        Fecha:todayStr(),Hora:timeHM(now)},"Movimientos");
      // Update status in Ninos sheet
      sheetdbPatch("ID",k.cid,{Estado:"Dentro",UltimaEntrada:timeHM(now)},"Ninos");
    }
  }
  function openCo(kid){setCoKid(kid);setScanOpen(true);setScanRes(null);}

  const doScan=useCallback(code=>{
    const kid=coKid;if(!kid)return;
    const kr=resps.filter(r=>kid.rids.includes(r.id));
    const match=kr.find(r=>{
      const rc=(r.id+todayStr()).slice(0,8).toUpperCase();
      return rc===code.toUpperCase()||pickupCode(kid.id)===code.toUpperCase();
    });
    if(match){
      setScanRes({ok:true,name:match.name});
      setTimeout(()=>{
        const now=new Date().toISOString();
        setKids(p=>p.map(c=>c.id===kid.id?{...c,in:false,log:[...(c.log||[]),{t:"out",at:now,by:match.name,rel:match.rel||""}]}:c));
        setDKid(p=>p&&p.id===kid.id?{...p,in:false}:p);
        sheetdbPost({ID:kid.cid,Nombre:kid.name,Evento:"Salida",Por:match.name,
          Relacion:match.rel||"",Fecha:todayStr(),Hora:timeHM(now)},"Movimientos");
        sheetdbPatch("ID",kid.cid,{Estado:"Fuera",UltimaRecogida:match.name,HoraRecogida:timeHM(now)},"Ninos");
        setScanOpen(false);setScanRes(null);setCoKid(null);
      },1800);
    }else{setScanRes({ok:false});setTimeout(()=>setScanRes(null),2500);}
  },[coKid,resps]);

  async function setPhoto(kid,file){
    if(!file)return;
    const d=await readF(file);
    setKids(p=>p.map(c=>c.id===kid.id?{...c,photo:d}:c));
    setDKid(p=>p&&p.id===kid.id?{...p,photo:d}:p);
  }
  function sendMsg(){
    if(!mF.title)return;
    const to=mF.to==="all"?"all":(mF.toUid||mF.toKid);
    setMsgs(p=>[...p,{id:"m"+Date.now(),title:mF.title,body:mF.body,
      to,alert:false,dis:[],at:new Date().toISOString()}]);
    setMF(eMsg);setMsgSearch("");setMsgMod(false);
  }
  function saveSched(){
    setSched(scF);setSchedMod(false);
    setMsgs(p=>[...p,{id:"s"+Date.now(),title:"📅 Horario actualizado",
      body:`Entrada: ${scF.s1}-${scF.e1} · Salida: ${scF.s2}-${scF.e2}`,
      to:"all",alert:false,dis:[],at:new Date().toISOString()}]);
  }

  const TABS=[
    {id:"dashboard",label:"📊 Tablón"},
    {id:"checkin",label:"✅ Check-in"},
    {id:"children",label:"👦 Niños"},
    {id:"messages",label:"📢 Comunicados"},
    {id:"reports",label:"📋 Reportes"},
    {id:"users",label:"👥 Usuarios"},
  ];

  return <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#f0f2f8,#e8eaf6)",fontFamily:"'DM Sans',sans-serif"}}>
    <style>{CSS}</style>
    <header style={{background:"#1a1a2e",padding:"0 14px",display:"flex",alignItems:"center",
      justifyContent:"space-between",height:56,boxShadow:"0 4px 24px #0003",position:"sticky",top:0,zIndex:800}}>
      <div style={{display:"flex",alignItems:"center",gap:9}}>
        <Logo size={32}/>
        <div>
          <div style={{color:"#fff",fontFamily:"Syne",fontWeight:800,fontSize:14,lineHeight:1}}>Iglesia La Hermosa</div>
          <div style={{color:"#a5b4fc",fontSize:10}}>Ministerio Infantil · Admin</div>
        </div>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:5}}>
        <div style={{background:"#22c55e20",border:"1.5px solid #22c55e50",borderRadius:99,
          padding:"2px 8px",color:"#4ade80",fontSize:11,fontWeight:700,display:"flex",alignItems:"center",gap:4}}>
          <Dot on/>{cin} dentro
        </div>
        {[["⏰",()=>{setScF(sched);setSchedMod(true);}],["📊",()=>setSheetsMod(true)],["Salir",onOut]].map(([l,fn])=>(
          <button key={l} onClick={fn} style={{border:"1px solid rgba(255,255,255,.2)",background:"transparent",
            color:"#a5b4fc",borderRadius:8,padding:"3px 8px",fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>{l}</button>
        ))}
      </div>
    </header>

    {stStatus&&<div style={{background:"#f0fdf4",borderBottom:"1px solid #bbf7d0",
      padding:"7px 16px",fontSize:13,fontWeight:600,color:"#16a34a",textAlign:"center"}}>{stStatus}</div>}

    <nav style={{background:"#fff",borderBottom:"1px solid #e5e7eb",padding:"0 12px",display:"flex",gap:1,overflowX:"auto"}}>
      {TABS.map(t=><button key={t.id} onClick={()=>setTab(t.id)} style={{background:"none",border:"none",
        cursor:"pointer",padding:"11px 11px",fontSize:12,fontWeight:600,fontFamily:"inherit",whiteSpace:"nowrap",
        color:tab===t.id?"#6366f1":"#6b7280",borderBottom:tab===t.id?"2.5px solid #6366f1":"2.5px solid transparent",
        position:"relative",display:"inline-flex",alignItems:"center",gap:5}}>
        {t.label}
        {t.id==="users"&&users.filter(u=>u.pending||u.role==="pending").length>0&&(
          <span style={{background:"#ef4444",color:"#fff",borderRadius:"50%",width:16,height:16,
            display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700}}>
            {users.filter(u=>u.pending||u.role==="pending").length}
          </span>
        )}
      </button>)}
    </nav>

    <main style={{maxWidth:960,margin:"0 auto",padding:"18px 12px",animation:"fIn .2s ease"}}>

      {/* TABLÓN */}
      {tab==="dashboard"&&<div>
        <h1 style={{fontFamily:"Syne",fontWeight:800,fontSize:22,color:"#1a1a2e",marginTop:0,marginBottom:16}}>Tablón</h1>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:10,marginBottom:16}}>
          {[{l:"Niños",v:kids.length,i:"👦",c:"#6366f1"},{l:"Dentro",v:cin,i:"✅",c:"#22c55e"},
            {l:"Responsables",v:resps.length,i:"👪",c:"#0ea5e9"},{l:"Alergias",v:kids.filter(c=>c.allergies).length,i:"⚠️",c:"#ef4444"}
          ].map(s=><div key={s.l} style={{background:"#fff",borderRadius:14,padding:"14px",
            boxShadow:"0 2px 10px #0001",borderTop:`3px solid ${s.c}`}}>
            <div style={{fontSize:22}}>{s.i}</div>
            <div style={{fontSize:26,fontWeight:800,fontFamily:"Syne",color:s.c,lineHeight:1.1,marginTop:4}}>{s.v}</div>
            <div style={{fontSize:12,color:"#6b7280",marginTop:2}}>{s.l}</div>
          </div>)}
        </div>
        {sched.s1&&<div style={{background:"#fff",borderRadius:14,padding:"12px 16px",
          boxShadow:"0 2px 10px #0001",marginBottom:14,display:"flex",gap:12,flexWrap:"wrap",alignItems:"center"}}>
          <span style={{fontSize:18}}>⏰</span>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,fontSize:13,color:"#1a1a2e"}}>Horario de hoy</div>
            <div style={{fontSize:12,color:"#6b7280"}}>Entrada: <b>{sched.s1}–{sched.e1}</b> · Recogida: <b>{sched.s2}–{sched.e2}</b></div>
          </div>
          <Btn onClick={()=>{setScF(sched);setSchedMod(true);}} outline small>Editar</Btn>
        </div>}
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(170px,1fr))",gap:10,marginBottom:14}}>
          {GROUPS.map(g=>{
            const tot=kids.filter(c=>groupOf(c).id===g.id).length;
            const ins=kids.filter(c=>groupOf(c).id===g.id&&c.in).length;
            return <div key={g.id} style={{background:"#fff",borderRadius:14,padding:"14px",
              boxShadow:"0 2px 10px #0001",border:`2px solid ${g.color}20`}}>
              <div style={{fontSize:26,marginBottom:6}}>{g.emoji}</div>
              <div style={{fontFamily:"Syne",fontWeight:800,fontSize:14,color:"#1a1a2e"}}>{g.label}</div>
              <div style={{color:"#9ca3af",fontSize:11,marginBottom:8}}>{g.id} años</div>
              <div style={{display:"flex",gap:10,marginBottom:8}}>
                <div><div style={{fontWeight:800,fontSize:16,color:g.color}}>{ins}</div><div style={{fontSize:10,color:"#9ca3af"}}>dentro</div></div>
                <div style={{width:1,background:"#f3f4f6"}}/>
                <div><div style={{fontWeight:800,fontSize:16,color:"#9ca3af"}}>{tot}</div><div style={{fontSize:10,color:"#9ca3af"}}>total</div></div>
              </div>
              <div style={{background:"#f3f4f6",borderRadius:99,height:4}}>
                <div style={{background:g.color,borderRadius:99,height:"100%",width:tot?`${ins/tot*100}%`:"0%",transition:"width .4s"}}/>
              </div>
            </div>;
          })}
        </div>
        {cin>0&&<>
          <h2 style={{fontFamily:"Syne",fontWeight:700,fontSize:15,color:"#1a1a2e",marginBottom:10}}>Dentro ahora 🏠</h2>
          <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
            {kids.filter(c=>c.in).map(c=><div key={c.id} style={{background:"#fff",borderRadius:10,
              padding:"5px 12px 5px 5px",display:"flex",alignItems:"center",gap:8,
              border:"1.5px solid #22c55e20",boxShadow:"0 1px 6px #0001"}}>
              <Ava photo={c.photo} emoji={groupOf(c).emoji} color={groupOf(c).color} size={26}/>
              <span style={{fontWeight:600,fontSize:13}}>{c.name}</span>
              <Badge g={groupOf(c)}/>
            </div>)}
          </div>
        </>}
      </div>}

      {/* CHECK-IN */}
      {tab==="checkin"&&<div>
        <h1 style={{fontFamily:"Syne",fontWeight:800,fontSize:22,color:"#1a1a2e",marginTop:0,marginBottom:14}}>Check-in / Check-out</h1>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Buscar niño..."
          style={{width:"100%",border:"2px solid #e5e7eb",borderRadius:12,padding:"10px 14px",
            fontSize:14,fontFamily:"inherit",marginBottom:12,outline:"none",boxSizing:"border-box"}}
          onFocus={e=>e.target.style.borderColor="#6366f1"} onBlur={e=>e.target.style.borderColor="#e5e7eb"}/>
        <div style={{display:"grid",gap:8}}>
          {filt.map(kid=>{
            const g=groupOf(kid);
            const lo=[...(kid.log||[])].reverse().find(a=>a.t==="out");
            return <div key={kid.id} style={{background:"#fff",borderRadius:14,padding:"11px 14px",
              boxShadow:"0 2px 10px #0001",display:"flex",alignItems:"center",gap:10,flexWrap:"wrap",
              borderLeft:`4px solid ${kid.in?"#22c55e":"#e5e7eb"}`}}>
              <Ava photo={kid.photo} emoji={g.emoji} color={g.color} size={36}/>
              <div style={{flex:1,minWidth:110}}>
                <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{kid.name}</div>
                <div style={{fontSize:10,color:"#9ca3af",fontFamily:"monospace",fontWeight:600}}>{kid.cid} · {kid.gender==="nina"?"👧":"👦"}</div>
                <div style={{display:"flex",gap:5,alignItems:"center",marginTop:3,flexWrap:"wrap"}}>
                  <Badge g={g}/>
                  {kid.allergies&&<span style={{background:"#fef2f2",color:"#ef4444",border:"1.5px solid #fecaca",
                    borderRadius:99,padding:"1px 6px",fontSize:10,fontWeight:700}}>⚠️ {kid.allergies}</span>}
                </div>
                {lo&&<div style={{fontSize:10,color:"#6b7280",marginTop:2}}>Última salida: <b>{lo.by}</b> · {timeHM(lo.at)}</div>}
              </div>
              <div style={{display:"flex",gap:5}}>
                {!kid.in
                  ?<Btn onClick={()=>doIn(kid.id)} color="#22c55e" small>✅ Entrada</Btn>
                  :<Btn onClick={()=>openCo(kid)} color="#ef4444" small>📷 Salida</Btn>}
                <Btn onClick={()=>setDKid(kid)} outline small>Ver</Btn>
              </div>
            </div>;
          })}
          {filt.length===0&&<div style={{textAlign:"center",color:"#9ca3af",padding:"32px 0"}}>Sin resultados</div>}
        </div>
      </div>}

      {/* NIÑOS */}
      {tab==="children"&&<div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14,flexWrap:"wrap",gap:8}}>
          <h1 style={{fontFamily:"Syne",fontWeight:800,fontSize:22,color:"#1a1a2e",margin:0}}>Niños registrados</h1>
          <Btn onClick={()=>{setKF(eKid);setAddKid(true);}}>+ Registrar</Btn>
        </div>
        <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap"}}>
          {[{id:"all",label:"Todos",emoji:"👥"},...GROUPS].map(g=><button key={g.id} onClick={()=>setFG(g.id)} style={{
            background:fG===g.id?"#6366f1":"#fff",color:fG===g.id?"#fff":"#374151",
            border:`2px solid ${fG===g.id?"#6366f1":"#e5e7eb"}`,
            borderRadius:99,padding:"4px 12px",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
            {g.emoji} {g.label}
          </button>)}
        </div>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍  Buscar..."
          style={{width:"100%",border:"2px solid #e5e7eb",borderRadius:12,padding:"10px 14px",
            fontSize:14,fontFamily:"inherit",marginBottom:12,outline:"none",boxSizing:"border-box"}}
          onFocus={e=>e.target.style.borderColor="#6366f1"} onBlur={e=>e.target.style.borderColor="#e5e7eb"}/>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))",gap:12}}>
          {filt.map(kid=>{
            const g=groupOf(kid);
            const kr=resps.filter(r=>kid.rids.includes(r.id));
            return <div key={kid.id} onClick={()=>setDKid(kid)} style={{
              background:"#fff",borderRadius:16,padding:"16px",boxShadow:"0 2px 10px #0001",
              cursor:"pointer",border:"2px solid transparent",transition:"all .15s"}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=g.color;e.currentTarget.style.transform="translateY(-2px)";}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor="transparent";e.currentTarget.style.transform="";}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:8,alignItems:"flex-start"}}>
                <div style={{display:"flex",gap:9,alignItems:"center"}}>
                  <Ava photo={kid.photo} emoji={g.emoji} color={g.color} size={36}/>
                  <div>
                    <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{kid.name}</div>
                    <div style={{color:"#9ca3af",fontSize:10}}>{kid.age} años · {kid.gender==="nina"?"👧 Niña":"👦 Niño"}</div>
                    <div style={{fontFamily:"monospace",fontSize:10,color:"#6b7280",fontWeight:600}}>{kid.cid}</div>
                  </div>
                </div>
                <Dot on={kid.in}/>
              </div>
              <Badge g={g}/>
              {kr.length>0&&<div style={{marginTop:6,fontSize:11,color:"#6b7280"}}>👪 {kr.map(r=>r.name).join(" · ")}</div>}
              {kid.allergies&&<div style={{marginTop:6,background:"#fef2f2",borderRadius:7,
                padding:"3px 8px",fontSize:11,color:"#dc2626",fontWeight:600}}>⚠️ {kid.allergies}</div>}
              <div style={{marginTop:7,display:"flex",gap:6,alignItems:"center"}}>
                <span style={{fontSize:10,color:"#9ca3af"}}>🔑</span>
                <span style={{fontFamily:"monospace",fontWeight:800,fontSize:13,color:"#6366f1",letterSpacing:2}}>{pickupCode(kid.id)}</span>
              </div>
            </div>;
          })}
        </div>
        {filt.length===0&&<div style={{textAlign:"center",color:"#9ca3af",padding:"32px 0"}}>Sin niños</div>}
      </div>}

      {/* COMUNICADOS */}
      {tab==="messages"&&<div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14,flexWrap:"wrap",gap:8}}>
          <h1 style={{fontFamily:"Syne",fontWeight:800,fontSize:22,color:"#1a1a2e",margin:0}}>Comunicados</h1>
          <Btn onClick={()=>{setMF(eMsg);setMsgSearch("");setMsgMod(true);}}>+ Nuevo</Btn>
        </div>
        {msgs.length===0&&<div style={{textAlign:"center",color:"#9ca3af",padding:"40px 0"}}>
          <div style={{fontSize:38,marginBottom:8}}>📢</div>Sin comunicados aún.
        </div>}
        <div style={{display:"grid",gap:10}}>
          {[...msgs].reverse().map(m=>(
            <div key={m.id} style={{background:"#fff",borderRadius:14,padding:"13px 16px",
              boxShadow:"0 2px 10px #0001",border:`1.5px solid ${m.auto?"#fde68a":"#e5e7eb"}`}}>
              <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
                <span style={{fontSize:20}}>{m.auto?"⏰":m.alert?"🔔":"📢"}</span>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{m.title}</div>
                  {m.body&&<div style={{fontSize:13,color:"#6b7280",marginTop:2}}>{m.body}</div>}
                  <div style={{display:"flex",gap:6,marginTop:5,flexWrap:"wrap"}}>
                    <span style={{background:"#f3f4f6",borderRadius:99,padding:"2px 8px",fontSize:11,color:"#6b7280"}}>
                      {m.to==="all"?"Para todos":"Para: "+( users.find(u=>u.id===m.to)?.name||m.to)}
                    </span>
                    <span style={{fontSize:11,color:"#9ca3af"}}>{timeFmt(m.at)}</span>
                  </div>
                </div>
                <button onClick={()=>setMsgs(p=>p.filter(x=>x.id!==m.id))}
                  style={{border:"none",background:"none",cursor:"pointer",color:"#d1d5db",fontSize:16}}
                  onMouseEnter={e=>e.currentTarget.style.color="#ef4444"}
                  onMouseLeave={e=>e.currentTarget.style.color="#d1d5db"}>🗑️</button>
              </div>
            </div>
          ))}
        </div>
      </div>}

      {/* REPORTES */}
      {tab==="reports"&&<div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14,flexWrap:"wrap",gap:8}}>
          <h1 style={{fontFamily:"Syne",fontWeight:800,fontSize:22,color:"#1a1a2e",margin:0}}>Reportes</h1>
          <Btn onClick={exportCSV} color="#16a34a" small>📊 Exportar</Btn>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(110px,1fr))",gap:10,marginBottom:16}}>
          {[{l:"Total",v:kids.length,c:"#6366f1"},{l:"Dentro",v:cin,c:"#22c55e"},
            {l:"Niños",v:kids.filter(c=>c.gender!=="nina").length,c:"#4fc3f7"},
            {l:"Niñas",v:kids.filter(c=>c.gender==="nina").length,c:"#f9a03f"},
            {l:"Alergias",v:kids.filter(c=>c.allergies).length,c:"#ef4444"}
          ].map(s=><div key={s.l} style={{background:"#fff",borderRadius:12,padding:"11px 13px",
            boxShadow:"0 2px 8px #0001",borderLeft:`4px solid ${s.c}`}}>
            <div style={{fontSize:18,fontWeight:800,fontFamily:"Syne",color:s.c}}>{s.v}</div>
            <div style={{fontSize:11,color:"#6b7280"}}>{s.l}</div>
          </div>)}
        </div>
        {GROUPS.map(g=>{
          const gk=[...kids.filter(c=>groupOf(c).id===g.id)].sort((a,b)=>a.name.localeCompare(b.name));
          if(!gk.length)return null;
          return <div key={g.id} style={{background:"#fff",borderRadius:16,overflow:"hidden",
            boxShadow:"0 2px 10px #0001",marginBottom:14,border:`2px solid ${g.color}20`}}>
            <div style={{padding:"10px 14px",borderBottom:"1px solid #f3f4f6",
              display:"flex",justifyContent:"space-between",alignItems:"center",background:g.bg}}>
              <span style={{fontFamily:"Syne",fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{g.emoji} {g.label} · {g.id} años</span>
              <span style={{fontSize:12,color:g.color,fontWeight:700}}>{gk.filter(c=>c.in).length}/{gk.length} presentes</span>
            </div>
            <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead><tr style={{background:"#f9fafb"}}>
                  {["ID","Nombre","Sexo","Estado","Responsables","Última recogida","Código recogida"].map(h=>(
                    <th key={h} style={{padding:"7px 12px",textAlign:"left",fontSize:10,fontWeight:700,
                      color:"#6b7280",letterSpacing:.5,textTransform:"uppercase",whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr></thead>
                <tbody>{gk.map((c,i)=>{
                  const rn=resps.filter(r=>c.rids.includes(r.id)).map(r=>r.name).join(", ");
                  const lo=[...(c.log||[])].reverse().find(a=>a.t==="out");
                  return <tr key={c.id} style={{background:i%2?"#fafafa":"#fff",borderBottom:"1px solid #f3f4f6"}}>
                    <td style={{padding:"8px 12px",fontFamily:"monospace",fontWeight:700,fontSize:11,color:"#6366f1"}}>{c.cid}</td>
                    <td style={{padding:"8px 12px",fontWeight:600,color:"#1a1a2e"}}>
                      <div style={{display:"flex",alignItems:"center",gap:6}}><Ava photo={c.photo} emoji={g.emoji} color={g.color} size={20}/>{c.name}</div>
                    </td>
                    <td style={{padding:"8px 12px"}}>{c.gender==="nina"?"👧 Niña":"👦 Niño"}</td>
                    <td style={{padding:"8px 12px"}}>
                      <span style={{background:c.in?"#dcfce7":"#f3f4f6",color:c.in?"#16a34a":"#9ca3af",
                        borderRadius:99,padding:"2px 8px",fontSize:10,fontWeight:700}}>
                        {c.in?"✅ Dentro":"🔲 Fuera"}
                      </span>
                    </td>
                    <td style={{padding:"8px 12px",fontSize:11,color:"#374151",maxWidth:140}}>{rn||"—"}</td>
                    <td style={{padding:"8px 12px",fontSize:11,color:"#6b7280"}}>
                      {lo?<span><b>{lo.by}</b><br/><span style={{fontSize:10,color:"#9ca3af"}}>{timeHM(lo.at)}</span></span>:"—"}
                    </td>
                    <td style={{padding:"8px 12px",fontFamily:"monospace",fontWeight:700,color:"#6366f1",letterSpacing:2,fontSize:11}}>{pickupCode(c.id)}</td>
                  </tr>;
                })}</tbody>
              </table>
            </div>
          </div>;
        })}
        {kids.some(c=>c.allergies)&&<div style={{background:"#fef2f2",borderRadius:14,padding:"13px 16px",border:"1.5px solid #fecaca"}}>
          <div style={{fontFamily:"Syne",fontWeight:700,fontSize:14,color:"#dc2626",marginBottom:10}}>⚠️ Alergias por grupo</div>
          {GROUPS.map(g=>{
            const wa=[...kids.filter(c=>groupOf(c).id===g.id&&c.allergies)].sort((a,b)=>a.name.localeCompare(b.name));
            if(!wa.length)return null;
            return <div key={g.id} style={{marginBottom:10}}>
              <div style={{fontSize:12,fontWeight:700,color:g.color,marginBottom:4}}>{g.emoji} {g.label}</div>
              {wa.map(c=><div key={c.id} style={{display:"flex",gap:10,fontSize:12,marginBottom:4,paddingLeft:8}}>
                <span style={{fontWeight:600,minWidth:130}}>{c.name}</span>
                <span style={{color:"#dc2626",fontWeight:600}}>{c.allergies}</span>
                {c.notes&&<span style={{color:"#6b7280"}}>— {c.notes}</span>}
              </div>)}
            </div>;
          })}
        </div>}
      </div>}
      {/* USUARIOS */}
      {tab==="users"&&<div>
        <h1 style={{fontFamily:"Syne",fontWeight:800,fontSize:22,color:"#1a1a2e",marginTop:0,marginBottom:16}}>Gestión de Usuarios</h1>

        {/* Pending approvals */}
        {users.filter(u=>u.pending||u.role==="pending").length>0&&<div style={{
          background:"#fef3c7",borderRadius:16,padding:"16px 18px",marginBottom:20,border:"1.5px solid #fde68a"}}>
          <div style={{fontFamily:"Syne",fontWeight:700,fontSize:15,color:"#d97706",marginBottom:12}}>
            ⏳ Cuentas pendientes de aprobación ({users.filter(u=>u.pending||u.role==="pending").length})
          </div>
          {users.filter(u=>u.pending||u.role==="pending").map(u=>(
            <div key={u.id} style={{background:"#fff",borderRadius:10,padding:"12px 14px",
              marginBottom:8,display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:14,color:"#1a1a2e"}}>{u.name}</div>
                <div style={{fontSize:12,color:"#6b7280"}}>{u.email}</div>
              </div>
              <div style={{display:"flex",gap:6}}>
                <Btn small color="#22c55e" onClick={()=>setUsers(p=>p.map(x=>x.id===u.id?{...x,role:"parent",pending:false}:x))}>
                  ✅ Aprobar padre
                </Btn>
                <Btn small color="#6366f1" onClick={()=>setUsers(p=>p.map(x=>x.id===u.id?{...x,role:"admin",pending:false}:x))}>
                  👑 Aprobar admin
                </Btn>
                <Btn small danger outline onClick={()=>setUsers(p=>p.filter(x=>x.id!==u.id))}>🗑️</Btn>
              </div>
            </div>
          ))}
        </div>}

        {/* All users */}
        <div style={{background:"#fff",borderRadius:16,overflow:"hidden",boxShadow:"0 2px 10px #0001"}}>
          <div style={{padding:"12px 16px",borderBottom:"1px solid #f3f4f6",fontFamily:"Syne",fontWeight:700,fontSize:14,color:"#1a1a2e"}}>
            Todos los usuarios ({users.filter(u=>!u.pending&&u.role!=="pending").length})
          </div>
          {users.filter(u=>!u.pending&&u.role!=="pending").map((u,i)=>(
            <div key={u.id} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 16px",
              borderBottom:"1px solid #f3f4f6",background:i%2?"#fafafa":"#fff",flexWrap:"wrap"}}>
              <div style={{width:36,height:36,borderRadius:10,
                background:u.role==="admin"?"#ede9fe":"#f0f9ff",
                display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>
                {u.role==="admin"?"👑":"👤"}
              </div>
              <div style={{flex:1}}>
                <div style={{fontWeight:600,fontSize:14,color:"#1a1a2e"}}>{u.name}</div>
                <div style={{fontSize:11,color:"#6b7280"}}>{u.email}</div>
              </div>
              <div style={{display:"flex",gap:6,alignItems:"center"}}>
                <span style={{
                  background:u.role==="admin"?"#ede9fe":"#f0f9ff",
                  color:u.role==="admin"?"#7c3aed":"#0369a1",
                  borderRadius:99,padding:"2px 10px",fontSize:11,fontWeight:700}}>
                  {u.role==="admin"?"Admin":"Padre"}
                </span>
                {u.id!==user.id&&<select value={u.role}
                  onChange={e=>setUsers(p=>p.map(x=>x.id===u.id?{...x,role:e.target.value}:x))}
                  style={{border:"1.5px solid #e5e7eb",borderRadius:8,padding:"4px 8px",fontSize:12,
                    fontFamily:"inherit",outline:"none",cursor:"pointer"}}>
                  <option value="parent">Padre</option>
                  <option value="admin">Admin</option>
                </select>}
                {u.id!==user.id&&<button onClick={()=>{if(window.confirm("¿Eliminar usuario?"))setUsers(p=>p.filter(x=>x.id!==u.id));}}
                  style={{border:"none",background:"none",cursor:"pointer",color:"#d1d5db",fontSize:14}}
                  onMouseEnter={e=>e.currentTarget.style.color="#ef4444"}
                  onMouseLeave={e=>e.currentTarget.style.color="#d1d5db"}>🗑️</button>}
              </div>
            </div>
          ))}
        </div>

        {/* Admin code info */}
        <div style={{background:"#f5f3ff",borderRadius:14,padding:"14px 16px",marginTop:16,border:"1.5px solid #c4b5fd"}}>
          <div style={{fontFamily:"Syne",fontWeight:700,fontSize:13,color:"#6366f1",marginBottom:6}}>🔐 Código de invitación para admins</div>
          <div style={{fontFamily:"monospace",fontWeight:800,fontSize:18,color:"#1a1a2e",letterSpacing:3,marginBottom:4}}>
            {ADMIN_INVITE_CODE}
          </div>
          <div style={{fontSize:12,color:"#6b7280"}}>Comparte este código solo con las personas de confianza que deban ser administradores.</div>
        </div>
      </div>}
    </main>

    {/* SCANNER */}
    <Modal open={scanOpen} onClose={()=>{setScanOpen(false);setScanRes(null);setCoKid(null);}}
      title={`📷 Verificar responsable${coKid?` — ${coKid.name}`:""}`}>
      {scanRes?<div style={{textAlign:"center",padding:"20px 0"}}>
        <div style={{fontSize:56}}>{scanRes.ok?"✅":"❌"}</div>
        <div style={{fontFamily:"Syne",fontWeight:800,fontSize:18,color:scanRes.ok?"#22c55e":"#ef4444",marginTop:10}}>
          {scanRes.ok?`¡Autorizado! ${scanRes.name}`:"No autorizado"}
        </div>
        <div style={{color:"#6b7280",marginTop:4,fontSize:13}}>
          {scanRes.ok?"Salida registrada":"Código no corresponde a un responsable autorizado"}
        </div>
      </div>:<QRScan onScan={doScan} onClose={()=>{setScanOpen(false);setCoKid(null);}}/>}
    </Modal>

    {/* ADD KID */}
    <Modal open={addKid} onClose={()=>setAddKid(false)} title="➕ Registrar niño/niña">
      <Inp label="Nombre completo" value={kF.name} onChange={v=>setKF(f=>({...f,name:v}))} placeholder="Ej: Ana García" required/>
      <Inp label="Edad" value={kF.age} onChange={v=>setKF(f=>({...f,age:v}))} placeholder="Ej: 7" type="number" required/>
      <div style={{marginBottom:14}}>
        <label style={{display:"block",fontSize:11,fontWeight:700,color:"#6b7280",marginBottom:6,letterSpacing:.5,textTransform:"uppercase"}}>SEXO *</label>
        <div style={{display:"flex",gap:8}}>
          {[["nino","👦 Niño"],["nina","👧 Niña"]].map(([v,l])=>(
            <button key={v} type="button" onClick={()=>setKF(f=>({...f,gender:v}))} style={{flex:1,
              border:`2px solid ${kF.gender===v?"#6366f1":"#e5e7eb"}`,
              background:kF.gender===v?"#6366f115":"#fff",borderRadius:10,padding:"10px",
              fontSize:14,fontWeight:700,cursor:"pointer",fontFamily:"inherit",
              color:kF.gender===v?"#6366f1":"#6b7280"}}>{l}</button>
          ))}
        </div>
      </div>
      <Inp label="Alergias" value={kF.allergies} onChange={v=>setKF(f=>({...f,allergies:v}))} placeholder="Ej: maní, lactosa"/>
      <Inp label="Notas" value={kF.notes} onChange={v=>setKF(f=>({...f,notes:v}))} placeholder="Observaciones..."/>
      <div style={{background:"#f0f9ff",borderRadius:9,padding:"8px 12px",fontSize:12,color:"#0369a1",marginBottom:14}}>
        💡 Se generará un ID fijo y un código de recogida diario automáticamente.
      </div>
      <div style={{display:"flex",gap:8}}>
        <Btn onClick={saveKid} full disabled={!kF.name||!kF.age}>Registrar</Btn>
        <Btn onClick={()=>setAddKid(false)} outline>Cancelar</Btn>
      </div>
    </Modal>

    {/* DETAIL KID */}
    <Modal open={!!dKid} onClose={()=>{setDKid(null);setAddR(false);setRF(eResp);}} title="👦 Perfil del niño" wide>
      {dKid&&(()=>{
        const g=groupOf(dKid);
        const kr=resps.filter(r=>dKid.rids.includes(r.id));
        return <div>
          <div style={{display:"flex",gap:14,alignItems:"flex-start",marginBottom:14}}>
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
              <label style={{cursor:"pointer"}}>
                <input type="file" accept="image/*" style={{display:"none"}} onChange={e=>setPhoto(dKid,e.target.files[0])}/>
                <div style={{position:"relative",width:60,height:60}}>
                  <Ava photo={dKid.photo} emoji={g.emoji} color={g.color} size={60}/>
                  <div style={{position:"absolute",bottom:-3,right:-3,background:"#6366f1",borderRadius:"50%",
                    width:20,height:20,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,color:"#fff"}}>📷</div>
                </div>
              </label>
              {dKid.photo&&<button onClick={()=>{setKids(p=>p.map(c=>c.id===dKid.id?{...c,photo:null}:c));setDKid(p=>p?{...p,photo:null}:p);}}
                style={{border:"none",background:"none",color:"#ef4444",fontSize:10,cursor:"pointer",padding:0}}>Quitar</button>}
            </div>
            <div style={{flex:1}}>
              <div style={{fontFamily:"Syne",fontWeight:800,fontSize:17,color:"#1a1a2e"}}>{dKid.name}</div>
              <div style={{fontSize:12,color:"#6b7280",marginTop:2}}>{dKid.age} años · {dKid.gender==="nina"?"👧 Niña":"👦 Niño"}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginTop:10}}>
                <div style={{background:"#f5f3ff",borderRadius:10,padding:"7px 10px"}}>
                  <div style={{fontSize:9,fontWeight:700,color:"#7c3aed",letterSpacing:.5,marginBottom:2}}>ID NIÑO (FIJO)</div>
                  <div style={{fontFamily:"monospace",fontWeight:800,fontSize:15,color:"#6366f1",letterSpacing:2}}>{dKid.cid}</div>
                </div>
                <div style={{background:"linear-gradient(135deg,#6366f1,#a78bfa)",borderRadius:10,padding:"7px 10px"}}>
                  <div style={{fontSize:9,fontWeight:700,color:"rgba(255,255,255,.7)",letterSpacing:.5,marginBottom:2}}>CÓDIGO RECOGIDA HOY</div>
                  <div style={{fontFamily:"monospace",fontWeight:800,fontSize:15,color:"#fff",letterSpacing:2}}>{pickupCode(dKid.id)}</div>
                </div>
              </div>
            </div>
          </div>
          {dKid.allergies&&<div style={{background:"#fef2f2",borderRadius:9,padding:"7px 12px",
            border:"1.5px solid #fecaca",marginBottom:8,fontSize:13,color:"#dc2626",fontWeight:600}}>⚠️ {dKid.allergies}</div>}
          {dKid.notes&&<div style={{background:"#f0f9ff",borderRadius:9,padding:"7px 12px",
            border:"1.5px solid #bae6fd",marginBottom:12,fontSize:13,color:"#0369a1"}}>📝 {dKid.notes}</div>}
          {/* Responsables */}
          <div style={{marginBottom:12}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
              <div style={{fontSize:11,fontWeight:700,color:"#6b7280",letterSpacing:.5,textTransform:"uppercase"}}>Responsables</div>
              <Btn onClick={()=>{setRF(eResp);setAddR(true);}} small>+ Agregar</Btn>
            </div>
            {kr.map(r=><div key={r.id} style={{display:"flex",gap:9,alignItems:"center",
              background:"#f9fafb",borderRadius:9,padding:"8px 10px",marginBottom:5}}>
              <div style={{width:32,height:32,borderRadius:9,background:"#ede9fe",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15}}>👤</div>
              <div style={{flex:1}}>
                <div style={{fontWeight:600,fontSize:13,color:"#1a1a2e"}}>{r.name}</div>
                <div style={{fontSize:11,color:"#6b7280"}}>{r.rel}{r.phone?` · ${r.phone}`:""}{r.email?` · ${r.email}`:""}</div>
                <div style={{display:"flex",gap:4,marginTop:2}}>
                  {r.nApp&&<span style={{background:"#ede9fe",color:"#7c3aed",borderRadius:99,padding:"1px 6px",fontSize:9,fontWeight:700}}>📱 App</span>}
                  {r.nSms&&<span style={{background:"#dcfce7",color:"#16a34a",borderRadius:99,padding:"1px 6px",fontSize:9,fontWeight:700}}>💬 SMS</span>}
                </div>
              </div>
              <button onClick={()=>delResp(r.id,dKid)}
                style={{border:"none",background:"none",cursor:"pointer",color:"#d1d5db",fontSize:14}}
                onMouseEnter={e=>e.currentTarget.style.color="#ef4444"}
                onMouseLeave={e=>e.currentTarget.style.color="#d1d5db"}>✕</button>
            </div>)}
            {kr.length===0&&<div style={{fontSize:12,color:"#9ca3af"}}>Sin responsables. Agrega uno.</div>}
          </div>
          {/* Add resp form */}
          {addR&&<div style={{background:"#f5f3ff",borderRadius:12,padding:"13px",border:"1.5px solid #c4b5fd",marginBottom:12}}>
            <div style={{fontFamily:"Syne",fontWeight:700,fontSize:13,color:"#6366f1",marginBottom:10}}>Nuevo responsable</div>
            <Inp label="Nombre" value={rF.name} onChange={v=>setRF(f=>({...f,name:v}))} placeholder="Nombre completo" required/>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              <Inp label="Teléfono" value={rF.phone} onChange={v=>setRF(f=>({...f,phone:v}))} placeholder="555-0000"/>
              <Inp label="Relación" value={rF.rel} onChange={v=>setRF(f=>({...f,rel:v}))} placeholder="Mamá / Papá..."/>
            </div>
            <Inp label="Email" value={rF.email} onChange={v=>setRF(f=>({...f,email:v}))} placeholder="correo@email.com" type="email"/>
            <div style={{marginBottom:12}}>
              <label style={{display:"block",fontSize:11,fontWeight:700,color:"#6b7280",marginBottom:6,letterSpacing:.5,textTransform:"uppercase"}}>NOTIFICACIONES</label>
              <div style={{display:"flex",gap:8}}>
                {[["nApp","📱 App"],["nSms","💬 SMS"]].map(([k,l])=>(
                  <label key={k} style={{display:"flex",alignItems:"center",gap:6,
                    background:rF[k]?"#f0f0ff":"#f9fafb",
                    border:`1.5px solid ${rF[k]?"#a5b4fc":"#e5e7eb"}`,
                    borderRadius:9,padding:"7px 10px",cursor:"pointer",flex:1,fontSize:12}}>
                    <input type="checkbox" checked={rF[k]} onChange={e=>setRF(f=>({...f,[k]:e.target.checked}))} style={{accentColor:"#6366f1"}}/>
                    <span style={{fontWeight:700,color:"#1a1a2e"}}>{l}</span>
                  </label>
                ))}
              </div>
            </div>
            <div style={{marginBottom:12}}>
              <label style={{display:"block",fontSize:11,fontWeight:700,color:"#6b7280",marginBottom:5,letterSpacing:.5,textTransform:"uppercase"}}>Vincular a cuenta (opcional)</label>
              <select value={rF.uid} onChange={e=>setRF(f=>({...f,uid:e.target.value}))}
                style={{width:"100%",border:"2px solid #e5e7eb",borderRadius:10,padding:"10px 14px",fontSize:14,fontFamily:"inherit",outline:"none"}}>
                <option value="">Sin cuenta vinculada</option>
                {users.filter(u=>u.role==="parent").map(u=><option key={u.id} value={u.id}>{u.name} ({u.email})</option>)}
              </select>
            </div>
            <div style={{display:"flex",gap:7}}>
              <Btn onClick={()=>saveResp(dKid)} small disabled={!rF.name}>Guardar</Btn>
              <Btn onClick={()=>setAddR(false)} outline small>Cancelar</Btn>
            </div>
          </div>}
          {/* Log */}
          {dKid.log?.length>0&&<div style={{marginBottom:12}}>
            <div style={{fontSize:11,fontWeight:700,color:"#6b7280",letterSpacing:.5,textTransform:"uppercase",marginBottom:6}}>Historial</div>
            {[...dKid.log].reverse().slice(0,6).map((a,i)=>(
              <div key={i} style={{display:"flex",gap:7,alignItems:"center",fontSize:12,marginBottom:5}}>
                <span>{a.t==="in"?"🟢":"🔵"}</span>
                <span style={{fontWeight:600}}>{a.t==="in"?"Entrada":"Salida"}</span>
                {a.by&&<span style={{color:"#6b7280"}}>— {a.by}{a.rel?` (${a.rel})`:""}</span>}
                <span style={{marginLeft:"auto",color:"#9ca3af",whiteSpace:"nowrap"}}>{timeFmt(a.at)}</span>
              </div>
            ))}
          </div>}
          <div style={{display:"flex",gap:7,paddingTop:8,borderTop:"1px solid #f3f4f6"}}>
            <Btn onClick={()=>{if(!dKid.in)doIn(dKid.id);else openCo(dKid);}}
              color={dKid.in?"#ef4444":"#22c55e"} style={{flex:1}}>
              {dKid.in?"📷 Check-out":"✅ Check-in"}
            </Btn>
            <Btn onClick={()=>{if(window.confirm("¿Eliminar este niño?"))delKid(dKid.id);}} danger outline small>🗑️</Btn>
          </div>
        </div>;
      })()}
    </Modal>

    {/* MSG MODAL */}
    <Modal open={msgMod} onClose={()=>setMsgMod(false)} title="📢 Nuevo comunicado">
      <div style={{marginBottom:14}}>
        <label style={{display:"block",fontSize:11,fontWeight:700,color:"#6b7280",marginBottom:6,letterSpacing:.5,textTransform:"uppercase"}}>DESTINATARIO</label>
        <div style={{display:"flex",gap:8,marginBottom:10}}>
          {[["all","👥 Todos los responsables"],["individual","👤 Responsable específico"]].map(([v,l])=>(
            <button key={v} onClick={()=>setMF(f=>({...f,to:v,toUid:"",toKid:""}))} style={{flex:1,
              border:`2px solid ${mF.to===v?"#6366f1":"#e5e7eb"}`,
              background:mF.to===v?"#6366f115":"#fff",borderRadius:10,padding:"8px 6px",
              fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",
              color:mF.to===v?"#6366f1":"#6b7280",lineHeight:1.3}}>{l}</button>
          ))}
        </div>
        {mF.to==="individual"&&<div>
          <input value={msgSearch} onChange={e=>setMsgSearch(e.target.value)} placeholder="🔍 Buscar niño..."
            style={{width:"100%",boxSizing:"border-box",border:"2px solid #e5e7eb",borderRadius:10,
              padding:"9px 14px",fontSize:13,fontFamily:"inherit",outline:"none",marginBottom:8}}
            onFocus={e=>e.target.style.borderColor="#6366f1"} onBlur={e=>e.target.style.borderColor="#e5e7eb"}/>
          {msgSearch&&<div style={{border:"2px solid #e5e7eb",borderRadius:10,maxHeight:130,overflowY:"auto",marginBottom:10}}>
            {kids.filter(c=>c.name.toLowerCase().includes(msgSearch.toLowerCase())).map(c=>(
              <div key={c.id} onClick={()=>{setMF(f=>({...f,toKid:c.id,toUid:""}));setMsgSearch("");}}
                style={{padding:"8px 14px",cursor:"pointer",fontSize:13,fontWeight:600,
                  borderBottom:"1px solid #f3f4f6",display:"flex",alignItems:"center",gap:8,
                  background:mF.toKid===c.id?"#f5f3ff":"#fff"}}>
                <Ava photo={c.photo} emoji={groupOf(c).emoji} color={groupOf(c).color} size={26}/>
                <div>
                  <div>{c.name}</div>
                  <div style={{fontSize:10,color:"#9ca3af"}}>{resps.filter(r=>c.rids.includes(r.id)).map(r=>r.name).join(", ")||"Sin responsables"}</div>
                </div>
              </div>
            ))}
          </div>}
          {mF.toKid&&(()=>{
            const sk=kids.find(c=>c.id===mF.toKid);
            const skr=resps.filter(r=>sk?.rids.includes(r.id));
            return <div style={{background:"#f9fafb",borderRadius:10,padding:"10px 14px",marginBottom:10}}>
              <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:8}}>
                <Ava photo={sk?.photo} emoji={groupOf(sk||{age:5}).emoji} color={groupOf(sk||{age:5}).color} size={28}/>
                <span style={{fontWeight:700,fontSize:14}}>{sk?.name}</span>
                <button onClick={()=>setMF(f=>({...f,toKid:"",toUid:""}))}
                  style={{border:"none",background:"none",color:"#9ca3af",cursor:"pointer",fontSize:13,marginLeft:"auto"}}>✕</button>
              </div>
              <div style={{fontSize:11,fontWeight:700,color:"#6b7280",marginBottom:5}}>ENVIAR A:</div>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                <button onClick={()=>setMF(f=>({...f,toUid:"all-"+mF.toKid}))}
                  style={{border:`2px solid ${mF.toUid==="all-"+mF.toKid?"#6366f1":"#e5e7eb"}`,
                    background:mF.toUid==="all-"+mF.toKid?"#6366f115":"#fff",
                    borderRadius:99,padding:"4px 12px",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",
                    color:mF.toUid==="all-"+mF.toKid?"#6366f1":"#6b7280"}}>Todos los responsables</button>
                {skr.map(r=><button key={r.id} onClick={()=>setMF(f=>({...f,toUid:r.uid||r.id}))}
                  style={{border:`2px solid ${mF.toUid===(r.uid||r.id)?"#6366f1":"#e5e7eb"}`,
                    background:mF.toUid===(r.uid||r.id)?"#6366f115":"#fff",
                    borderRadius:99,padding:"4px 12px",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",
                    color:mF.toUid===(r.uid||r.id)?"#6366f1":"#6b7280"}}>👤 {r.name}</button>)}
              </div>
            </div>;
          })()}
        </div>}
      </div>
      <Inp label="Título" value={mF.title} onChange={v=>setMF(f=>({...f,title:v}))} placeholder="Ej: Reunión de padres" required/>
      <div style={{marginBottom:14}}>
        <label style={{display:"block",fontSize:11,fontWeight:700,color:"#6b7280",marginBottom:5,letterSpacing:.5,textTransform:"uppercase"}}>MENSAJE (opcional)</label>
        <textarea value={mF.body} onChange={e=>setMF(f=>({...f,body:e.target.value}))} placeholder="Detalles..."
          rows={3} style={{width:"100%",boxSizing:"border-box",border:"2px solid #e5e7eb",borderRadius:10,
            padding:"10px 14px",fontSize:14,fontFamily:"inherit",outline:"none",resize:"vertical"}}
          onFocus={e=>e.target.style.borderColor="#6366f1"} onBlur={e=>e.target.style.borderColor="#e5e7eb"}/>
      </div>
      <div style={{display:"flex",gap:8}}>
        <Btn onClick={sendMsg} full disabled={!mF.title||(mF.to==="individual"&&!mF.toKid)}>Enviar</Btn>
        <Btn onClick={()=>setMsgMod(false)} outline>Cancelar</Btn>
      </div>
    </Modal>

    {/* SCHEDULE MODAL */}
    <Modal open={schedMod} onClose={()=>setSchedMod(false)} title="⏰ Horario del servicio">
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:6}}>
        <Inp label="Entrada desde" value={scF.s1} onChange={v=>setScF(f=>({...f,s1:v}))} type="time"/>
        <Inp label="Entrada hasta"  value={scF.e1} onChange={v=>setScF(f=>({...f,e1:v}))} type="time"/>
        <Inp label="Recogida desde" value={scF.s2} onChange={v=>setScF(f=>({...f,s2:v}))} type="time"/>
        <Inp label="Recogida hasta" value={scF.e2} onChange={v=>setScF(f=>({...f,e2:v}))} type="time"/>
      </div>
      <div style={{background:"#fef3c7",borderRadius:9,padding:"8px 12px",fontSize:12,color:"#92400e",marginBottom:14,border:"1.5px solid #fde68a"}}>
        🔔 Se notificará a todos los padres y la app enviará recordatorio a la hora de recogida.
      </div>
      <div style={{display:"flex",gap:8}}>
        <Btn onClick={saveSched} full>Guardar</Btn>
        <Btn onClick={()=>setSchedMod(false)} outline>Cancelar</Btn>
      </div>
    </Modal>

    {/* SHEETS MODAL */}
    <Modal open={sheetsMod} onClose={()=>setSheetsMod(false)} title="📊 Google Sheets">
      <div style={{background:"#f0fdf4",borderRadius:10,padding:"11px 14px",border:"1.5px solid #bbf7d0",marginBottom:14,fontSize:13,color:"#15803d"}}>
        Cada entrada/salida se enviará automáticamente a tu hoja de Google Sheets.
      </div>
      <div style={{fontSize:12,color:"#6b7280",marginBottom:12,lineHeight:1.7}}>
        <b>Pasos:</b> Ve a <b>script.google.com</b> → Nuevo proyecto → Pega el código del manual → Despliega como app web → Copia la URL aquí.
      </div>
      <Inp label="URL de tu Apps Script" value={sheetsUrl} onChange={v=>{setSheetsUrl(v);sv("mi_su",v);}} placeholder="https://script.google.com/macros/s/.../exec"/>
      {sheetsUrl&&<div style={{background:"#f0fdf4",borderRadius:8,padding:"8px 12px",fontSize:12,color:"#16a34a",marginTop:-6,marginBottom:12}}>
        ✅ URL guardada — sincronización activa
      </div>}
      <div style={{display:"flex",gap:8}}>
        <Btn onClick={()=>{exportCSV();setSheetsMod(false);}} full color="#16a34a">Probar exportación</Btn>
        <Btn onClick={()=>setSheetsMod(false)} outline>Cerrar</Btn>
      </div>
    </Modal>
  </div>;
}

/* ══════════════════════════════════════════════════════════════════════
   ROOT
══════════════════════════════════════════════════════════════════════ */
export default function App(){
  const [users,   setUsers]  = useState(()=>ld("mi_u4",  S_USERS));
  const [kids,    setKids]   = useState(()=>ld("mi_k4",  S_KIDS));
  const [resps,   setResps]  = useState(()=>ld("mi_r4",  S_RESP));
  const [msgs,    setMsgs]   = useState(()=>ld("mi_m4",  []));
  const [sched,   setSched]  = useState(()=>ld("mi_s4",  S_SCHED));
  const [session, setSession]= useState(()=>ld("mi_ss4", null));

  useEffect(()=>sv("mi_u4",  users),  [users]);
  useEffect(()=>sv("mi_k4",  kids),   [kids]);
  useEffect(()=>sv("mi_r4",  resps),  [resps]);
  useEffect(()=>sv("mi_m4",  msgs),   [msgs]);
  useEffect(()=>sv("mi_s4",  sched),  [sched]);
  useEffect(()=>sv("mi_ss4", session),[session]);

  const me=session?users.find(u=>u.id===session.id)||session:null;
  if(!me)return <Login users={users} onLogin={setSession} onReg={u=>{setUsers(p=>[...p,u]);setSession(u);}}/>;
  if(me.role==="parent")return <ParentView user={me} kids={kids} resps={resps}
    msgs={msgs} setMsgs={setMsgs} sched={sched} onOut={()=>setSession(null)}/>;
  return <AdminView user={me} users={users} setUsers={setUsers}
    kids={kids} setKids={setKids} resps={resps} setResps={setResps}
    msgs={msgs} setMsgs={setMsgs} sched={sched} setSched={setSched}
    onOut={()=>setSession(null)}/>;
}
